/**
 * Build a mock async generator that yields the supplied events in order.
 */
async function* makeStream(
  events: AiStreamEvent[],
): AsyncGenerator<AiStreamEvent> {
  for (const event of events) {
    yield event;
  }
}

/**
 * Read all SSE text from a Response whose body is a ReadableStream.
 */
async function readSSE(response: Response): Promise<string> {
  const reader = response.body!.getReader();
  const decoder = new TextDecoder();
  let result = "";
  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    result += decoder.decode(value);
  }
  return result;
}

/**
 * Parse SSE text into an array of { event, data } objects.
 */
function parseSSEEvents(raw: string): Array<{ event: string; data: unknown }> {
  const events: Array<{ event: string; data: unknown }> = [];
  const blocks = raw.split("\n\n").filter((b) => b.trim());
  for (const block of blocks) {
    let eventName = "";
    let dataLine = "";
    for (const line of block.split("\n")) {
      if (line.startsWith("event: "))
        eventName = line.slice("event: ".length).trim();
      if (line.startsWith("data: "))
        dataLine = line.slice("data: ".length).trim();
    }
    if (eventName && dataLine) {
      try {
        events.push({ event: eventName, data: JSON.parse(dataLine) });
      } catch {
        events.push({ event: eventName, data: dataLine });
      }
    }
  }
  return events;
}

